    45→        .unwrap_or_else(std::time::Instant::now);
    46→
    47→    // Recover orphans from previous crashes on startup
    48→    let recovered = reaper::recover_orphans(&running_dir, &pending_dir).await?;
    49→    if !recovered.is_empty() {
    50→        eprintln!(
    51→            "[dispatcher] recovered {} orphaned cards: {:?}",
    52→            recovered.len(),
    53→            recovered
    54→        );
    55→    }
    56→
    57→    let lineage_enabled = bop_core::lineage::is_enabled(cards_dir);
    58→    let mut shown_empty_hint = false;
    59→
    60→    // Set up filesystem watcher with 100ms debounce on pending/
    61→    let (tx, mut rx) = tokio_mpsc::unbounded_channel();
    62→    let pending_dir_clone = pending_dir.clone();
    63→
    64→    std::thread::spawn(move || {
    65→        let (std_tx, std_rx) = std::sync::mpsc::channel();
    66→        let mut debouncer = match new_debouncer(Duration::from_millis(100), std_tx) {
    67→            Ok(d) => d,
    68→            Err(e) => {
    69→                eprintln!("[dispatcher] failed to create watcher: {}", e);
    70→                return;
    71→            }
    72→        };
    73→
    74→        if let Err(e) = debouncer
    75→            .watcher()
    76→            .watch(&pending_dir_clone, notify::RecursiveMode::Recursive)
    77→        {
    78→            eprintln!("[dispatcher] failed to watch pending/: {}", e);
    79→            return;
    80→        }
    81→
    82→        for res in std_rx {
    83→            match res {
    84→                Ok(events) => {
    85→                    // Filter to only .bop directory events
    86→                    let relevant = events.iter().any(|e| {
    87→                        e.path.extension().and_then(|s| s.to_str()) == Some("bop")
    88→                            && matches!(
    89→                                e.kind,
    90→                                DebouncedEventKind::Any | DebouncedEventKind::AnyContinuous
    91→                            )
    92→                    });
    93→                    if relevant {
    94→                        let _ = tx.send(());
    95→                    }
    96→                }
    97→                Err(e) => {
    98→                    eprintln!("[dispatcher] watch error: {}", e);
    99→                }
   100→            }

