     2→
     3→/// Power state of the system
     4→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
     5→pub enum SleepState {
     6→    /// System is awake and running normally
     7→    Awake,
     8→    /// System is preparing to sleep or asleep
     9→    Sleeping,
    10→}
    11→
    12→#[cfg(all(target_os = "macos", feature = "iokit"))]
    13→pub fn spawn_power_watcher(tx: watch::Sender<SleepState>) {
    14→    use core_foundation::runloop::{kCFRunLoopCommonModes, CFRunLoop};
    15→    use std::ffi::c_void;
    16→    use std::os::raw::{c_int, c_long, c_ulong};
    17→    use std::sync::{Arc, Mutex};
    18→    use std::time::{Duration, Instant};
    19→
    20→    // IOKit constants
    21→    const K_IO_MESSAGE_SYSTEM_WILL_SLEEP: c_ulong = 0xe0000280;
    22→    const K_IO_MESSAGE_SYSTEM_HAS_POWERED_ON: c_ulong = 0xe0000300;
    23→
    24→    // IOKit types
    25→    type IoObject = c_int;
    26→    type IoConnect = c_int;
    27→
    28→    // IOKit FFI declarations
    29→    #[link(name = "IOKit", kind = "framework")]
    30→    extern "C" {
    31→        fn IORegisterForSystemPower(
    32→            refcon: *mut c_void,
    33→            port_ref: *mut IoObject,
    34→            callback: extern "C" fn(*mut c_void, IoConnect, c_ulong, *mut c_void),
    35→            notifier: *mut IoObject,
    36→        ) -> IoObject;
    37→        fn IODeregisterForSystemPower(notifier: *mut IoObject) -> c_int;
    38→        fn IOAllowPowerChange(kernelPort: IoConnect, notificationID: c_long) -> c_int;
    39→        fn IOCancelPowerChange(kernelPort: IoConnect, notificationID: c_long) -> c_int;
    40→        fn IONotificationPortGetRunLoopSource(notify: IoObject) -> *mut c_void;
    41→    }
    42→
    43→    // Context passed to the IOKit callback
    44→    struct CallbackContext {
    45→        tx: watch::Sender<SleepState>,
    46→        sleep_deadline: Arc<Mutex<Option<Instant>>>,
    47→    }
    48→
    49→    extern "C" fn power_callback(
    50→        refcon: *mut c_void,
    51→        service: IoConnect,
    52→        message_type: c_ulong,
    53→        message_argument: *mut c_void,
    54→    ) {
    55→        unsafe {
    56→            let ctx = &mut *(refcon as *mut CallbackContext);
    57→
    58→            match message_type {
    59→                K_IO_MESSAGE_SYSTEM_WILL_SLEEP => {
    60→                    // Notify that system is going to sleep
    61→                    let _ = ctx.tx.send(SleepState::Sleeping);
    62→
    63→                    // Set 8-second deadline
    64→                    *ctx.sleep_deadline.lock().unwrap() = Some(Instant::now());
    65→
    66→                    // Allow power change immediately
    67→                    // The dispatcher will handle pausing running cards on its own timeline
    68→                    IOAllowPowerChange(service, message_argument as c_long);
    69→                }
    70→                K_IO_MESSAGE_SYSTEM_HAS_POWERED_ON => {
    71→                    // Clear deadline
    72→                    *ctx.sleep_deadline.lock().unwrap() = None;
    73→
    74→                    // Notify that system has woken up
    75→                    let _ = ctx.tx.send(SleepState::Awake);
    76→                }
    77→                _ => {}
    78→            }
    79→        }
    80→    }
    81→
    82→    std::thread::spawn(move || {
    83→        unsafe {
    84→            let mut root_port: IoObject = 0;
    85→            let mut notifier: IoObject = 0;
    86→
    87→            let sleep_deadline = Arc::new(Mutex::new(None::<Instant>));
    88→            let ctx = Box::new(CallbackContext {
    89→                tx: tx.clone(),
    90→                sleep_deadline: sleep_deadline.clone(),
    91→            });
    92→            let ctx_ptr = Box::into_raw(ctx);
    93→
    94→            let notifier_object = IORegisterForSystemPower(
    95→                ctx_ptr as *mut c_void,
    96→                &mut root_port,
    97→                power_callback,
    98→                &mut notifier,
    99→            );
   100→
   101→            if notifier_object == 0 {
   102→                eprintln!("[power] Failed to register for system power notifications");
   103→                drop(Box::from_raw(ctx_ptr));
   104→                return;
   105→            }
   106→
   107→            let rls = IONotificationPortGetRunLoopSource(root_port);
   108→            if !rls.is_null() {
   109→                CFRunLoop::get_current().add_source(
   110→                    &core_foundation::runloop::CFRunLoopSource::wrap_under_create_rule(rls),
   111→                    unsafe { kCFRunLoopCommonModes },
   112→                );
   113→            }
   114→
   115→            // Spawn deadline monitor thread
   116→            let deadline_clone = sleep_deadline.clone();
   117→            std::thread::spawn(move || loop {
   118→                std::thread::sleep(Duration::from_secs(1));
   119→                if let Some(deadline) = *deadline_clone.lock().unwrap() {
   120→                    if deadline.elapsed() > Duration::from_secs(8) {
   121→                        eprintln!(
   122→                            "[power] Warning: sleep deadline exceeded (8s), \
   123→                             system may have been held"
   124→                        );
   125→                        *deadline_clone.lock().unwrap() = None;
   126→                    }
   127→                }
   128→            });
   129→
   130→            // Run the CFRunLoop (blocks until shutdown)
   131→            CFRunLoop::run_current();
   132→
   133→            // Cleanup
   134→            IODeregisterForSystemPower(&mut notifier);
   135→            drop(Box::from_raw(ctx_ptr));
   136→        }
   137→    });
   138→}
