    12→///
    13→/// **Critical constraint (macOS)**: IORegisterForSystemPower and the IOKit run loop
    14→/// MUST run on a dedicated OS thread (not a tokio task). Tokio tasks can be starved
    15→/// under load, and if IOAllowPowerChange is not called promptly after
    16→/// kIOMessageSystemWillSleep, macOS will hang the sleep transition for the full
    17→/// kernel timeout (~30s).
    18→///
    19→/// On macOS: Uses IOKit to subscribe to system power notifications.
    20→/// On Linux: Stub implementation (feature-gated for future zbus integration).
    21→/// On other platforms: No-op (always returns Awake state).
    22→pub fn spawn_power_watcher() -> tokio::sync::watch::Receiver<SleepState> {
    23→    let (tx, rx) = tokio::sync::watch::channel(SleepState::Awake);
    24→
    25→    #[cfg(target_os = "macos")]
    26→    spawn_macos_watcher(tx);
    27→
    28→    #[cfg(target_os = "linux")]
    29→    spawn_linux_watcher(tx);
    30→
    31→    #[cfg(not(any(target_os = "macos", target_os = "linux")))]
    32→    {
    33→        // No-op for other platforms
    34→        let _ = tx;
    35→    }
    36→
    37→    rx
    38→}
