    27→/// Checks if a failure reason indicates a transient network error.
    28→/// Returns true if the failure is likely due to network issues that may be
    29→/// resolved by retrying after a delay.
    30→fn is_network_failure(failure_reason: &Option<String>) -> bool {
    31→    let Some(ref reason) = failure_reason else {
    32→        return false;
    33→    };
    34→
    35→    let reason_lower = reason.to_lowercase();
    36→
    37→    // Common network error patterns
    38→    reason_lower.contains("connection refused")
    39→        || reason_lower.contains("connection timed out")
    40→        || reason_lower.contains("connection timeout")
    41→        || reason_lower.contains("connection reset")
    42→        || reason_lower.contains("connection closed")
    43→        || reason_lower.contains("network unreachable")
    44→        || reason_lower.contains("network is unreachable")
    45→        || reason_lower.contains("host unreachable")
    46→        || reason_lower.contains("no route to host")
    47→        || reason_lower.contains("dns resolution failed")
    48→        || reason_lower.contains("could not resolve host")
    49→        || reason_lower.contains("name resolution failed")
    50→        || reason_lower.contains("temporary failure in name resolution")
    51→        || reason_lower.contains("tls handshake")
    52→        || reason_lower.contains("ssl handshake")
    53→        || reason_lower.contains("certificate verify failed")
    54→        || reason_lower.contains("502 bad gateway")
    55→        || reason_lower.contains("503 service unavailable")
    56→        || reason_lower.contains("504 gateway timeout")
    57→        || reason_lower.contains("socket closed")
    58→        || reason_lower.contains("socket error")
    59→        || reason_lower.contains("broken pipe")
    60→        || reason_lower.contains("unexpected eof")
    61→        || reason_lower.contains("connection aborted")
    62→        || reason_lower.contains("no internet connection")
    63→        || reason_lower.contains("network error")
    64→        || reason_lower.contains("dns error")
    65→        || reason_lower.contains("timed out")
    66→}
