    39→fn validate_provider(name: &str, p: &Provider) -> anyhow::Result<()> {
    40→    if name.trim().is_empty() {
    41→        anyhow::bail!("provider name cannot be empty");
    42→    }
    43→    if p.command.trim().is_empty() {
    44→        anyhow::bail!("provider '{}': command/adapter cannot be empty", name);
    45→    }
    46→    Ok(())
    47→}
