    49→fn providers_path(cards_dir: &Path) -> PathBuf {
    50→    cards_dir.join("providers.json")
    51→}
    52→
    53→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    54→    let p = providers_path(cards_dir);
    55→    if !p.exists() {
    56→        return Ok(ProvidersFile::default());
    57→    }
    58→    let bytes = fs::read(p)?;
    59→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    60→    for (name, provider) in &pf.providers {
    61→        validate_provider(name, provider)?;
    62→    }
    63→    Ok(pf)
    64→}
    65→
    66→pub fn write_providers(cards_dir: &Path, pf: &ProvidersFile) -> anyhow::Result<()> {
    67→    for (name, provider) in &pf.providers {
    68→        validate_provider(name, provider)?;
    69→    }
    70→    let bytes = serde_json::to_vec_pretty(pf)?;
    71→
    72→    let target = providers_path(cards_dir);
    73→    let tmp = target.with_extension("json.tmp");
    74→
    75→    fs::write(&tmp, &bytes)?;
    76→    fs::rename(&tmp, &target)?;
    77→
    78→    Ok(())
    79→}
