   124→pub fn rotate_provider_chain(meta: &mut Meta) {
   125→    if meta.provider_chain.len() <= 1 {
   126→        return;
   127→    }
   128→    let first = meta.provider_chain.remove(0);
   129→    meta.provider_chain.push(first);
   130→}
   131→
   132→pub fn select_provider(
   133→    cards_dir: &Path,
   134→    meta: Option<&mut Meta>,
   135→    stage: &str,
   136→) -> anyhow::Result<Option<ProviderSelection>> {
   137→    let pf = read_providers(cards_dir)?;
   138→    let now = Utc::now().timestamp();
   139→
   140→    let avoid_provider = if stage == "qa" {
   141→        meta.as_ref()
   142→            .and_then(|m| m.stages.get("implement"))
   143→            .and_then(|r| r.provider.clone())
   144→    } else {
   145→        None
   146→    };
   147→
   148→    let chain: Vec<String> = match meta {
   149→        Some(m) => {
   150→            if m.provider_chain.is_empty() {
   151→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   152→            }
   153→            m.provider_chain.clone()
   154→        }
   155→        None => vec!["mock".to_string(), "mock2".to_string()],
   156→    };
   157→
   158→    let mut fallback: Option<ProviderSelection> = None;
   159→    for name in chain {
   160→        let Some(p) = pf.providers.get(&name) else {
   161→            continue;
   162→        };
   163→        if let Some(until) = p.cooldown_until_epoch_s {
   164→            if until > now {
   165→                continue;
   166→            }
   167→        }
   168→
   169→        if let Some(ref avoid) = avoid_provider {
   170→            if &name == avoid {
   171→                if fallback.is_none() {
   172→                    fallback = Some((
   173→                        name,
   174→                        p.command.clone(),
   175→                        p.rate_limit_exit,
   176→                        p.env.clone(),
   177→                        p.model.clone(),
   178→                    ));
   179→                }
   180→                continue;
   181→            }
   182→        }
   183→
   184→        return Ok(Some((
   185→            name,
   186→            p.command.clone(),
   187→            p.rate_limit_exit,
   188→            p.env.clone(),
   189→            p.model.clone(),
   190→        )));
   191→    }
   192→
   193→    Ok(fallback)
   194→}
   195→
   196→pub fn set_provider_cooldown(
   197→    cards_dir: &Path,
   198→    provider: &str,
   199→    cooldown_s: i64,
   200→) -> anyhow::Result<()> {
   201→    let mut pf = read_providers(cards_dir)?;
   202→    let now = Utc::now().timestamp();
   203→    if let Some(p) = pf.providers.get_mut(provider) {
   204→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   205→    }
   206→    write_providers(cards_dir, &pf)?;
   207→    Ok(())
   208→}
